    // Function to get the current screen size and orientation
    func getScreenSizeAndOrientation() -> (size: CGSize, orientation: String) {
        var screenSize = UIScreen.main.bounds.size
        
        if let orientation = UIDevice.current.orientation.rawValue {
            switch orientation {
            case 1:
                return (screenSize, "Portrait")
            case 2:
                return (screenSize, "Landscape")
            default:
                return (screenSize, "Unknown")
            }
        } else {
            print("Error retrieving screen size and orientation")
            return (CGSize.zero, "")
        }
    }
